#!/bin/bash# NICTO Colab Data Upload Instructions# =====================================# Option 1: Manual upload to Google Drive#   1. Zip kaggle_data/#      tar -czf kaggle_data.tar.gz kaggle_data/#   2. Upload to Google Drive root#   3. In Colab notebook, mount Drive:#      from google.colab import drive#      drive.mount('/content/drive')#   4. Extract:#      !tar -xzf /content/drive/MyDrive/kaggle_data.tar.gz -C /content/## Option 2: Direct download in Colab (if hosted on GitHub releases)#   !wget -q https://github.com/stephenwahogo0-arch/NICTO/releases/download/data/kaggle_data.tar.gz#   !tar -xzf kaggle_data.tar.gz## Option 3: Use Kaggle API (if datasets are on Kaggle)#   !kaggle datasets download stephenwahogo0/nicto-training-data#   !unzip nicto-training-data.zip